/*
 * 创建人：tian.he
 * 函数名：创建时
 * 描述：刷新生产单元实例列表
 * 步骤：
    1、获取树数据
    2、构建树形结构
    3、渲染树组件
    4、触发查询生产单元实例详情执行
 * 参数：
 * 返回值：
 */

debugger

// ====================== 常量定义 ======================
const CALL_BY_NAME = 2;
const API_TYPE = 21001; // 接口类型标识
const TIMEOUT = 1000 * 60 * 5; // 接口请求超时时间

class TagGroupManager {
    constructor() {
        this.requestParams = this.initRequestParams();
    }

    /** 初始化请求参数 */
    initRequestParams() {
        return new StringMap({
            "cloudID": $Variable.cloudID,
            "type": API_TYPE,
            "timeout": TIMEOUT
        });
    }

    /** 主执行流程 */
    async execute() {
        try {
            // 向父页面传参
            let parentPageName = "运维部署管理_框架页面";
            let selectedNodeStatus = {
                undeployNodeCount: 0,
                deployedStartedCount: 0,
                deployedStoppedCount: 0
            };
            SetVariable(parentPageName, 'selectedNodeStatus', selectedNodeStatus);
            // 触发父页面脚本执行
            GetVariable(parentPageName, 'updatePUButtonStatus');

            // 获取树数据
            let rawData = [];
            let showExpands = 生产单元实例表格.propData.expands;
            let expandsGUID = []  // 需要展开的行，以purepoguid为标志
            let selectArea = $Variable.selectPUInstancesList;
            let puRepoGuid = selectArea[0].purepoguid;
            // 判断全局对象缓存中是否存在key
            if ($Variable.tableDataMap.hasOwnProperty(puRepoGuid)) {
                // 从全局对象缓存中获取数据
                rawData = $Variable.tableDataMap[puRepoGuid];
                expandsGUID.push(puRepoGuid);
            } else {
                // 调后台接口获取数据
                rawData = await this.queryPUInstancesList(puRepoGuid, selectArea[0].timespaceguid, expandsGUID);
            }
            let mergedArray = rawData;
            // expands.push(rawData[0]);
            while (rawData.length > 0) {
                // 并发查询下级子数据
                const batchPromises = rawData.map(rawDataItem =>
                    this.queryPUInstancesList(rawDataItem.purepoguid, rawDataItem.timespaceguid, expandsGUID)
                );
                // 等待全部执行完毕
                const batchResults = await Promise.all(batchPromises);
                // 返回数据合并
                let temp_RawData = [];
                for (let i = 0; i < batchResults.length; i++) {
                    let batchResultArr = batchResults[i];

                    if (batchResultArr.length > 0) {
                        mergedArray = [...mergedArray, ...batchResultArr];
                    }
                    // 往全局对象缓存中添加数据
                    $Variable.tableDataMap[rawData[i].purepoguid] = batchResultArr;
                    temp_RawData = [...temp_RawData, ...batchResultArr];
                }
                
                rawData = temp_RawData;
            }    
                // 更新缓存
                const new_rawData = mergeAndUpdateCache(mergedArray, expandsGUID);
                // 构建树形结构
                const treeData = this.buildTreeStructure(new_rawData);
                // 渲染表格树组件
                生产单元实例表格.SetData(treeData);
                // 生产单元实例表格.defaultExpandAll =true
                // let exp = getRowIndex(expandsGUID, 生产单元实例表格.propData.data);
                let exp = forGetRowIndex(expandsGUID, 生产单元实例表格.propData.data);
                setTimeout(() => {
                生产单元实例表格.propData.expands = exp;
                },50)

            // 清空选中数据
            $Variable.selectPUInstancesList = [];
        } catch (error) {
            this.handleError('主流程执行异常', error);
        } finally {
            // 
        }
    }

    /** 查询生产单元实例列表数据 */
    queryPUInstancesList(selectRepoGUID, parentTSGuid, expandsGUIDSets) {
        return new Promise((resolve, reject) => {
            // let areaInfo = new StringMap({
            //     "默认数据区": 0
            // });
            // $Variable.areaID = areaInfo;
            let inputParamMap = new StringMap({
                "parentTSGuid": parentTSGuid || ""
            });
            inputParamMap._insert("rootRepositoryGUID", $Variable.rootRepositoryGUID, "string"); // string;工程_Root仓库GUID
            inputParamMap._insert("selectRepoGUID", selectRepoGUID, "string"); // string;选择的仓库GUID
            inputParamMap._insert("deployCloudGUID", new StringMap(JSON.parse($Variable.cloudInfos))); // string;部署云区域GUID
            inputParamMap._insert("areaID", new StringMap($Variable.areaID));
            let inputParam = new Variant(inputParamMap);

            const input = new StringMap({
                identifierType: CALL_BY_NAME,
                name: $Variable.spaceTimeObjectName,
                funcname: "IQueryPUInstancesList",
                params: [inputParam]
            });

            let pjtMngSTFullPath = $Variable.spaceTimeObjectFullPath;
            let runInfo = {
                stType: 5, // FULLNAME，使用全路径名标识，其他标识参数无效
                spaceTime: pjtMngSTFullPath // 目标页面的时空属性，和sTType配合使用
            }
            SetRunInfo(runInfo, async (resData) => {
                if (0 === resData.ret) {

                    let res = await Call(this.requestParams, input);

                    try {
                        if (0 !== res.ret) {
                            let errormsg = "请求发送失败！请检查后台服务是否运行正常";
                            _Infor(errormsg, "error");
                            return reject("-E- " + errormsg + "，errorCode:" + res.ret);
                        }

                        if (res.errorcodes) {
                            for (let i = 0; i < res.errorcodes.length; i++) {
                                let res_errorcode = res.errorcodes[i];
                                if (0 !== res_errorcode) {
                                    _Infor("查询失败！", "error");
                                    return reject("-E- IQueryPUInstancesList()接口错误，errorCode:" + res_errorcode);
                                }
                            }
                        }

                        if (res.returndata) {
                            let res_returndata = res.returndata;
                            if (0 !== res_returndata.errorcode) {
                                _Infor("查询失败！", "error");
                                return reject("-E- " + res_returndata.errormsg + "，errorCode:" + res_returndata.errorcode);
                            }

                            // 返回表格数据
                            if(res_returndata.puinstanceslist.length > 0){
                                expandsGUIDSets.push(selectRepoGUID);
                            }
                            return resolve(res_returndata.puinstanceslist);
                        }

                    } catch (error) {
                        // 保留原始错误栈信息 
                        return reject(`-E- 查询失败！${error.message}`);
                    }
                } else {
                    let errormsg = resData.msg;
                    return reject("-E- " + errormsg + "，errorCode:" + resData.ret);
                }
            });
        });
    }

    /** 构建树形结构 */
    buildTreeStructure(dataSet) {
        const nodeMap = new Map();
        const pendingLinks = new Map();
        const tree = [];

        dataSet.forEach(item => {
            const node = this.createNode(item);
            nodeMap.set(node.purepoguid, node);

            const parentname = item.purepoparentguid;
            if (!parentname) {
                tree.push(node);
            } else {
                this.linkToParent(parentname, node, nodeMap, pendingLinks);
            }

            // 处理延迟挂载的子节点 
            if (pendingLinks.has(node.purepoguid)) {
                node.children.push(...pendingLinks.get(node.purepoguid));
                pendingLinks.delete(node.purepoguid);
            }
        });

        this.handleOrphanNodes(pendingLinks, tree);
        return tree;
    }

    /** 创建树节点 */
    createNode(rawItem) {
        return {
            "purepoguid": rawItem.purepoguid,
            "purepoid": rawItem.purepoid,
            "instance_name": rawItem.instance_name,
            "timespaceguid": rawItem.timespaceguid,
            "purepoparentguid": rawItem.purepoparentguid,
            "parenttsguid": rawItem.parenttsguid,
            "current_version": "未部署" === rawItem.deploy_state ? "无" : rawItem.current_version,
            "deploy_state": rawItem.deploy_state,
            "running_state": rawItem.running_state,
            // "id": rawItem.id,
            "rowIndex": rawItem.rowIndex,
            "cloudname":rawItem.cloudname,
            "areaname": rawItem.areaname,
            "children": []
        };
    }

    /** 节点挂载处理 */
    linkToParent(parentName, childNode, nodeMap, pendingMap) {
        if (nodeMap.has(parentName)) {
            nodeMap.get(parentName).children.push(childNode);
        } else {
            pendingMap.set(parentName, [...(pendingMap.get(parentName) || []), childNode]);
        }
    }

    /** 处理孤儿节点 */
    handleOrphanNodes(pendingMap, tree) {
        pendingMap.forEach((nodes, parentName) => {
            console.warn(` 未找到父节点 ${parentName}，将作为根节点挂载`);
            nodes.forEach(node => {
                tree.push(node);
                if (pendingMap.has(node.purepoguid)) {
                    node.children.push(...pendingMap.get(node.purepoguid));
                    pendingMap.delete(node.purepoguid);
                }
            });
        });
    }

    /** 统一错误处理 */
    handleError(context, error) {
        console.error(`[${context}]`, error);
        _Infor(`${context}: ${error.message}`, 'error');
    }
}

/**
 * 合并更新缓存数组
 * @param {Array} rawData - 新查询到的数据数组
 * @param {string} primaryKey - 对象主键，默认为 'purepoguid'
 * @returns {Array} 更新后的缓存数组
 */
function mergeAndUpdateCache(rawData, expandGUIDSets, primaryKey = 'purepoguid') {
    let expandIndex = [];
    if (!Array.isArray(rawData)) {
        console.error('rawData 必须是一个数组');
        return $Variable.tableData;
    }

    // 如果没有缓存数据，直接使用新数据
    if ($Variable.tableData.length === 0) {
        $Variable.tableData = [...rawData];
        console.log('初始化缓存数据，数量:', $Variable.tableData.length);
        return $Variable.tableData;
    }

    // 创建缓存数据的映射，便于快速查找
    const cacheMap = new Map();
    $Variable.tableData.forEach(item => {
        const key = item[primaryKey];
        if (key) {
            cacheMap.set(key, item);
        }
    });

    // 合并数据：新数据覆盖旧数据，同时保留不在新数据中的旧数据
    rawData.forEach(newItem => {
        const key = newItem[primaryKey];
        if (key) {
            cacheMap.set(key, newItem);
        }
    });

    // 转换回数组
    $Variable.tableData = Array.from(cacheMap.values());
    
    // 添加id作为展开标识
    for(i = 0; i < $Variable.tableData.length; i++){
        let member = $Variable.tableData[i];
        // member["id"] = i+1;
        member["rowIndex"] = i+1;
        if(expandGUIDSets.indexOf(member.purepoguid) >= 0){
            expandIndex.push(i+1);
        }
    }
    $Variable.expandIndex = expandIndex;
    console.log('缓存更新完成，总数量:', $Variable.tableData.length);
    return $Variable.tableData;
}

// 递归寻找rowIndex
function getRowIndex(idList, dataList) {
    const rowIndexList = [];
    function setRowIndexList(data) {
        if(data.children && data.children.length) {
            const idObjParent = idList.find(el => el === data.purepoguid);
            if(idObjParent) {
                rowIndexList.push(data.rowIndex)
            }            
            data.children.forEach(item => {
                setRowIndexList(item);
            })   
        }else {
            const idObj = idList.find(el => el === data.purepoguid);
            if(idObj) {
                rowIndexList.push(data.rowIndex)
            }
        }
    }
    dataList.forEach(item => {
        setRowIndexList(item)
    })
    return rowIndexList
}

// 一次性寻找rowIndex返回map结构
function forGetRowIndex(idList, dataList){
    let rowIndexMap = {};
    function catchChildren(data){
        if(data.children && data.children.length){
            rowIndexMap[data.purepoguid] = data.rowIndex;
            data.children.forEach(item => {
                catchChildren(item);
            })
        }else{
            rowIndexMap[data.purepoguid] = data.rowIndex;
        }
    }
    dataList.forEach(item => {
        catchChildren(item);
    })
    let rowIndexSets = [];
    for(i = 0; i < idList.length; i++){
        rowIndexSets.push(rowIndexMap[idList[i]]);
    }
    return rowIndexSets;
}

function _Infor(message, type = 'error') {
    ShowMessage({
        message,
        type,
        duration: 3000,
        showClose: true
    });
}

// ====================== 执行 ======================
new TagGroupManager().execute();

