// 获取当前子页面名称
let currentPageName = $Variable.currentPageName;

// 触发子页面部署函数执行
switch (currentPageName) {
    case '管控单元实例_页面':
        if (0 === 管控单元实例_页面.$Variable.selectPUInstancesList.length) {
            _Infor("请选择节点！", "error");
        }else{
            let noSpace = true;
            let spaceInfo = new Set();
            let selectPU = new Set();
            let selectParentPU = new Set();
            for(i = 0; i < 管控单元实例_页面.$Variable.selectPUInstancesList.length; i++){
                let cloudname = 管控单元实例_页面.$Variable.selectPUInstancesList[i].cloudname;
                let areaname = 管控单元实例_页面.$Variable.selectPUInstancesList[i].areaname;
                selectPU.add(管控单元实例_页面.$Variable.selectPUInstancesList[i].purepoguid);
                selectParentPU.add(管控单元实例_页面.$Variable.selectPUInstancesList[i].purepoparentguid);
                if("" == cloudname){
                    noSpace = false;
                }else{
                    spaceInfo.add(cloudname+"_"+areaname);
                }
            }
            let difference = new Set([...selectParentPU].filter((x) => !selectPU.has(x)));
            let dep = true;
            for(i = 0; i < 管控单元实例_页面.$Variable.tableData.length; i++){
                if(管控单元实例_页面.$Variable.tableData[i].purepoguid in difference){
                    if(管控单元实例_页面.$Variable.tableData[i].cloudname == ""){
                         _Infor("请先部署父节点！", "error");
                         dep = false;
                         break;
                    }
                }
            }

            if(dep){
                if((spaceInfo.size == 1 && noSpace == false) || spaceInfo.size == 0 || (spaceInfo.size == 1 && noSpace == true)){
                    let windowHeight = document.body.clientHeight;
                    let pageHeight = 200;
                    let topPX = "0px";
                    if ((windowHeight - pageHeight) > 0) {
                        topPX = String((windowHeight - pageHeight) / 2 - 100) + "px";
                    }
                    //页面名称
                    let pageName = "数据区选择_页面";
                    //配置项
                    let options = {
                        styleOptions: {
                            header: false,
                            modal: true,
                            width: 700,
                            height: 360,
                            draggable: true,
                            maximizable: false,
                            top: topPX
                        },
                        variables: [{
                            name: "batchDeployInfo",
                            value: Array.from(spaceInfo)
                        },{
                            name: "kind",
                            value:"批量部署"
                        }]
                    };

                    let choseCloud = "";
                    let choseArea = "";
                    let choseCloudGUID = "";
                    let choseAreaID = 0;
                    if((spaceInfo.size == 1 && noSpace == false) || spaceInfo.size == 0){
                        ShowChild(pageName, options, (res) => {
                            debugger
                            if (res.eventName == "closePageEvent") {
                                let deploy = true;
                                if (res.eventParam.length > 0) {
                                    choseCloud = res.eventParam[0].cloudname;
                                    choseArea = res.eventParam[0].areaname;
                                    choseCloudGUID = res.eventParam[0].cloudguid;
                                    choseAreaID = res.eventParam[0].areaid;
                                    if(spaceInfo.size == 1){
                                        if(Array.from(spaceInfo)[0] != choseCloud+"_"+choseArea){
                                            _Infor(`请选择云${choseCloud}，数据区${choseArea}部署`, "warning");
                                            CloseChild(pageName);
                                            deploy = false;
                                        }
                                    }    
                                    CloseChild(pageName);

                                    if(deploy){
                                        管控单元实例_页面.$Variable.choseCloud = JSON.stringify([choseCloudGUID, choseAreaID, choseCloud, choseArea]);
                                        管控单元实例_页面.$Variable.batchDeployPUInstances = !管控单元实例_页面.$Variable.batchDeployPUInstances;                                     
                                    }
                                }else{
                                    CloseChild(pageName);
                                }
                            }
                        });                 
                    }else{
                        管控单元实例_页面.$Variable.choseCloud = JSON.stringify([choseCloudGUID, choseAreaID, choseCloud, choseArea]);
                        管控单元实例_页面.$Variable.batchDeployPUInstances = !管控单元实例_页面.$Variable.batchDeployPUInstances;                    
                    }
                }else if(spaceInfo.size > 1){
                    _Infor("所选节点处于不同数据区或云，请分开部署", "warning");
                }                
            }
        }

        break;
    case '数字孪生可视化_页面':
        if(0 == 数字孪生可视化_页面.$Variable.selectDTInstancesList.length){
            _Infor("请选择节点！", "error");
        }else{
            let cloudSets = new Set();
            let noTermSpace = 0;
            for(i = 0; i < 数字孪生可视化_页面.$Variable.selectDTInstancesList.length; i++){
                if("" == 数字孪生可视化_页面.$Variable.selectDTInstancesList[i].timespaceguid){
                    noTermSpace++
                }else{
                    cloudSets.add(数字孪生可视化_页面.$Variable.selectDTInstancesList[i].cloudguid);
                }
            }

            if((cloudSets.size == 0 || cloudSets.size == 1) && noTermSpace > 0){
                let windowHeight = document.body.clientHeight;
                let pageHeight = 200;
                let topPX = "0px";
                if ((windowHeight - pageHeight) > 0) {
                    topPX = String((windowHeight - pageHeight) / 2 - 100) + "px";
                }
                //页面名称
                let pageName = "数据区选择_页面";
                //配置项
                let options = {
                    styleOptions: {
                        header: false,
                        modal: true,
                        width: 700,
                        height: 360,
                        draggable: true,
                        maximizable: false,
                        top: topPX
                    },
                    variables: [{
                        name: "kind",
                        value:"批量部署"
                    }]
                }; 

                ShowChild(pageName, options, (res) => {
                    debugger
                    if (res.eventName == "closePageEvent") {
                        let deploy = true;
                        if (res.eventParam.length > 0) {
                            choseCloud = res.eventParam[0].cloudname;
                            choseArea = res.eventParam[0].areaname;
                            choseCloudGUID = res.eventParam[0].cloudguid;
                            choseAreaID = res.eventParam[0].areaid;
                            if(cloudSets.size == 1){
                                if(Array.from(cloudSets)[0] != choseCloudGUID){
                                    _Infor(`请选择云${choseCloud}，数据区${choseArea}部署`, "warning");
                                    CloseChild(pageName);
                                    deploy = false;
                                }
                            }    
                            CloseChild(pageName);

                            if(deploy){
                                let dpInfo = {};
                                dpInfo.cloudguid = choseCloudGUID;
                                dpInfo.areaid = choseAreaID;
                                数字孪生可视化_页面.$Variable.deployInfo = JSON.stringify(dpInfo);
                                数字孪生可视化_页面.$Variable.batchDeployDTInstances = !数字孪生可视化_页面.$Variable.batchDeployDTInstances;                                     
                            }
                        }else{
                            CloseChild(pageName);
                        }
                    }
                });                 
            }else if(noTermSpace == 0 && cloudSets.size == 1){
                数字孪生可视化_页面.$Variable.batchDeployDTInstances = !数字孪生可视化_页面.$Variable.batchDeployDTInstances;
            }else if(cloudSets.size > 1){
                _Infor("所选数据区属于不同云区域，请根据云批量部署",'warning');
            }
        }
        // 数字孪生可视化_页面.$Variable.batchDeployDTInstances = !数字孪生可视化_页面.$Variable.batchDeployDTInstances;
        break;
    case '系统服务配置_页面':
        系统服务配置_页面.$Variable.batchDeployDTInstances = !系统服务配置_页面.$Variable.batchDeployDTInstances;
        break;
    default:
        break;
}

// 消息提示窗函数
function _Infor(massage, type) {
    var options = {
        message: massage,
        type: type,
        duration: 3000,
        showClose: true
    };
    ShowMessage(options);
}

