            if (rawData.length > 0) {
                // 并发查询下级子数据
                const batchPromises = rawData.map(rawDataItem =>
                    this.queryPUInstancesList(rawDataItem.purepoguid, rawDataItem.purepoguid) // rawDataItem.timespaceguid
                );
                // 等待全部执行完毕
                const batchResults = await Promise.all(batchPromises);
                // 返回数据合并
                let mergedArray = rawData;
                for (let i = 0; i < batchResults.length; i++) {
                    let batchResultArr = batchResults[i];

                    if (batchResultArr.length > 0) {
                        mergedArray = [...mergedArray, ...batchResultArr];
                    }
                    // 往全局对象缓存中添加数据
                    $Variable.tableDataMap[rawData[i].purepoguid] = batchResultArr;
                }
                // 更新缓存
                const new_rawData = mergeAndUpdateCache(mergedArray);
                // 构建树形结构
                const treeData = this.buildTreeStructure(new_rawData);
                // 渲染表格树组件
                生产单元实例表格.SetData(treeData);
            }

            // 清空选中数据
            $Variable.selectPUInstancesList = [];
