    $Variable.tableData.forEach(item => {
        const key = item[primaryKey];
        if (key) {
            cacheMap.set(key, item);
        }
    });

    // 先更新所有缓存对象
    rawData.forEach(newItem => {
        const key = newItem[primaryKey];
        if (key) {
            // 更新对象自身信息
