    /** 查询生产单元实例列表数据 */
    queryPUInstancesInfo() {
        return new Promise((resolve, reject) => {

            let inputParamMap = new StringMap({});

            let PUMapInfo = new StringMap({});
            let reposGUID = [];
            let timeSpacesGUID = [];
            for (let i = 0; i < $Variable.selectPUInstancesList.length; i++) {
                let puInstanceItem = $Variable.selectPUInstancesList[i];

                let paramMap = new StringMap({});
                paramMap._insert("purepoguid", puInstanceItem.purepoguid, "string"); // string;<实例仓库GUID>
                paramMap._insert("purepoid", puInstanceItem.purepoid, "uint64"); // uint64;<实例仓库ID>
                paramMap._insert("instance_name", puInstanceItem.instance_name, "string"); // string;<实例名称>
                paramMap._insert("timespaceguid", puInstanceItem.timespaceguid, "string"); // string;<实例时空对象GUID>
                paramMap._insert("purepoparentguid", puInstanceItem.purepoparentguid, "string"); // string;<实例仓库父仓库GUID>
                paramMap._insert("parenttsguid", puInstanceItem.parenttsguid, "string"); // string;<父时空对象GUID>
                paramMap._insert("current_version", puInstanceItem.current_version, "string");
                paramMap._insert("deploy_state", puInstanceItem.deploy_state, "string");
                paramMap._insert("running_state", puInstanceItem.running_state, "string");

                PUMapInfo._insert(puInstanceItem.purepoguid, paramMap, "stringmap<var>");
                reposGUID.push(puInstanceItem.purepoguid);
                timeSpacesGUID.push(puInstanceItem.timespaceguid);
            }

            // 部署、批量部署做特殊处理
            if ("部署" === $Variable.commandType || "批量部署" === $Variable.commandType) {
                timeSpacesGUID = $Variable.timeSpaceGuids;
            }

            inputParamMap._insert("PUMapInfo", PUMapInfo, "stringmap<var>"); // stringMap<var>;实例仓库信息map
            inputParamMap._insert("reposGUID", reposGUID, "string[]"); // string[];实例仓库GUID数组
            inputParamMap._insert("timeSpacesGUID", timeSpacesGUID, "string[]"); // string[];实例时空对象GUID数组

            const input = new StringMap({
                identifierType: CALL_BY_NAME,
                name: $Variable.spaceTimeObjectName,
                funcname: "IQueryPUInstancesInfo",
                params: [new Variant(inputParamMap)]
            });

            let pjtMngSTFullPath = $Variable.spaceTimeObjectFullPath;
            let runInfo = {
                stType: 5, // FULLNAME，使用全路径名标识，其他标识参数无效
                spaceTime: pjtMngSTFullPath // 目标页面的时空属性，和sTType配合使用
            }
            SetRunInfo(runInfo, async (resData) => {
                if (0 === resData.ret) {

                    let res = await Call(this.requestParams, input);

                    try {
                        if (0 !== res.ret) {
                            let errormsg = "请求发送失败！请检查后台服务是否运行正常";
                            _Infor(errormsg, "error");
                            return reject("-E- " + errormsg + "，errorCode:" + res.ret);
                        }

                        if (res.errorcodes) {
                            for (let i = 0; i < res.errorcodes.length; i++) {
                                let res_errorcode = res.errorcodes[i];
                                if (0 !== res_errorcode) {
                                    _Infor("查询失败！", "error");
                                    return reject("-E- IQueryPUInstancesInfo()接口错误，errorCode:" + res_errorcode);
                                }
                            }
                        }

                        if (res.returndata) {
                            let res_returndata = res.returndata;
                            if (0 !== res_returndata.errorcode) {
                                _Infor("查询失败！", "error");
                                return reject("-E- " + res_returndata.errormsg + "，errorCode:" + res_returndata.errorcode);
                            }

                            // 返回表格数据
                            return resolve(res_returndata.puinstanceslist);
                        }

                    } catch (error) {
                        // 保留原始错误栈信息 
                        return reject(`-E- 查询失败！${error.message}`);
                    }
                } else {
                    let errormsg = resData.msg;
                    return reject("-E- " + errormsg + "，errorCode:" + resData.ret);
                }
            });
        });
    }

    /** 构建树形结构 */
    buildTreeStructure(dataSet) {
        const nodeMap = new Map();
        const pendingLinks = new Map();
        const tree = [];

        dataSet.forEach(item => {
            const node = this.createNode(item);
            nodeMap.set(node.purepoguid, node);

            const parentname = item.purepoparentguid;
            if (!parentname) {
                tree.push(node);
            } else {
                this.linkToParent(parentname, node, nodeMap, pendingLinks);
            }

            // 处理延迟挂载的子节点 
            if (pendingLinks.has(node.purepoguid)) {
                node.children.push(...pendingLinks.get(node.purepoguid));
                pendingLinks.delete(node.purepoguid);
            }
        });

        this.handleOrphanNodes(pendingLinks, tree);
        return tree;
    }

    /** 创建树节点 */
    createNode(rawItem) {
        return {
            "purepoguid": rawItem.purepoguid,
            "purepoid": rawItem.purepoid,
            "instance_name": rawItem.instance_name,
            "timespaceguid": rawItem.timespaceguid,
            "purepoparentguid": rawItem.purepoparentguid,
            "parenttsguid": rawItem.parenttsguid,
            "current_version": "未部署" === rawItem.deploy_state ? "无" : rawItem.current_version,
            "deploy_state": rawItem.deploy_state,
            "running_state": rawItem.running_state,
            "cloudname": rawItem.cloudname,
            "areaname": rawItem.areaname,
            "children": []
        };
    }

    /** 节点挂载处理 */
    linkToParent(parentName, childNode, nodeMap, pendingMap) {
        if (nodeMap.has(parentName)) {
            nodeMap.get(parentName).children.push(childNode);
        } else {
            pendingMap.set(parentName, [...(pendingMap.get(parentName) || []), childNode]);
        }
    }

    /** 处理孤儿节点 */
    handleOrphanNodes(pendingMap, tree) {
        pendingMap.forEach((nodes, parentName) => {
            console.warn(` 未找到父节点 ${parentName}，将作为根节点挂载`);
            nodes.forEach(node => {
                tree.push(node);
                if (pendingMap.has(node.purepoguid)) {
                    node.children.push(...pendingMap.get(node.purepoguid));
                    pendingMap.delete(node.purepoguid);
                }
            });
        });
    }

    /** 统一错误处理 */
    handleError(context, error) {
        console.error(`[${context}]`, error);
        _Infor(`${context}: ${error.message}`, 'error');
    }
}

/**
 * 合并更新缓存数组
 * @param {Array} rawData - 新查询到的数据数组
 * @param {string} primaryKey - 对象主键，默认为 'purepoguid'
 * @returns {Array} 更新后的缓存数组
 */
function mergeAndUpdateCache(rawData, primaryKey = 'purepoguid') {
    if(rawData.length > 0){
        let updateMember = {};
        for(i = 0; i < rawData.length; i++){
            let parentguid = rawData[i].purepoparentguid;
            if(parentguid != "" ){
                let temp;
                if(updateMember[parentguid] == undefined){
                    temp = [];
                    temp.push(rawData[i]);
                    updateMember[parentguid] = temp;
                }else{
                    temp = updateMember[parentguid];
                    temp.push(rawData[i]);
                }
                
            }
        }
        Object.entries(updateMember).forEach(([key, value])=>{
            $Variable.tableDataMap[key] = value
        });
        // let currentParent = rawData[1].purepoparentguid;
        // let cache = $Variable.tableDataMap;
        // cache[currentParent] = rawData;
        // $Variable.tableDataMap = cache;
    }
    
    if (!Array.isArray(rawData)) {
        console.error('rawData 必须是一个数组');
        return $Variable.tableData;
    }

    // 如果没有缓存数据，直接使用新数据
    if ($Variable.tableData.length === 0) {
        $Variable.tableData = [...rawData];
        console.log('初始化缓存数据，数量:', $Variable.tableData.length);
        return $Variable.tableData;
    }

    // 创建缓存数据的映射，便于快速查找
    const cacheMap = new Map();
    $Variable.tableData.forEach(item => {
        const key = item[primaryKey];
        if (key) {
            cacheMap.set(key, item);
        }
    });

    // 先更新所有缓存对象
    rawData.forEach(newItem => {
        const key = newItem[primaryKey];
        if (key) {
            // 更新对象自身信息
            cacheMap.set(key, newItem);
        }
    });

    if ("部署" === $Variable.commandType || "批量部署" === $Variable.commandType) {
        // 然后处理父子关系：更新子元素的parenttsguid
        rawData.forEach(newItem => {
            const parentGuid = newItem[primaryKey]; // 自身对象的purepoguid
            const timeSpaceGuid = newItem.timespaceguid; // 自身对象的timespaceguid

            // 只有当前对象有timespaceguid时才进行处理
            if (parentGuid && timeSpaceGuid) {
                // 在缓存中查找所有purepoparentguid等于当前对象purepoguid的元素
                cacheMap.forEach(item => {
                    // 检查该元素是否以当前对象为父元素
                    if (item.purepoparentguid === parentGuid) {
                        // 更新该元素的parenttsguid为当前对象的timespaceguid
                        item.parenttsguid = timeSpaceGuid;
                        // console.log(`更新子元素 ${item[primaryKey]} 的parenttsguid为: ${timeSpaceGuid}`);
                    }
                });
            }
        });
    }

    // 转换回数组
    $Variable.tableData = Array.from(cacheMap.values());

    console.log('缓存更新完成，总数量:', $Variable.tableData.length);
    return $Variable.tableData;
}

