 * 函数名：deployPUInstances
 * 描述：部署生产单元实例
 * 步骤：
 * 参数：
 * 返回值：
 */

debugger

// 声明call函数常量
const CALL_BY_NAME = 2;
const API_TYPE = 21001; // 接口类型标识
const TIMEOUT = 1000 * 60 * 10; // 接口请求超时时间
const PARAM_PUBLIC = new StringMap({
    "cloudID": $Variable.cloudID,
    "type": API_TYPE,
    "timeout": TIMEOUT
});

// 消息提示窗函数
function _Infor(massage, type) {
    var options = {
        message: massage,
        type: type,
        duration: 3000,
        showClose: true
    };
    ShowMessage(options);
}

// 部署生产单元实例函数
function _DeployPUInstances(puInstanceItem) {
    return new Promise((resolve, reject) => {
        // 打开遮罩层
        let options = {
            text: "加载中...",
            background: 'rgba(30, 28, 28, 0.5)'
        };
        let loadItem = ShowLoading(options);
        
        let cloudInfo = JSON.parse($Variable.cloudInfos);
        let paramMap = new StringMap({});
        paramMap._insert("instRepoGUID", puInstanceItem.purepoguid, "string"); // string;根实例仓库GUID
        paramMap._insert("instRepoName", puInstanceItem.instance_name, "string"); // string;根实例仓库名称
        paramMap._insert("parentGUID", puInstanceItem.parenttsguid, "string"); // string;父时空GUID
        if("" != puInstanceItem.cloudname && undefined != puInstanceItem.cloudname){
            paramMap._insert("deployCloudGUID", cloudInfo[puInstanceItem.cloudname], "string"); // string;部署云区域GUID
            paramMap._insert("areaID", $Variable.areaID[puInstanceItem.areaname], "int32");  // int32;数据区ID
            paramMap._insert("cloudAreaName", [puInstanceItem.cloudname, puInstanceItem.areaname], "string[]");            
        }else{
            if("" == $Variable.deployInfo){
                _Infor("请选择部署的云和数据区", "error");
                return resolve(-1);
            }else{
                let deployInfo = JSON.parse($Variable.deployInfo);
                // let parent = puInstanceItem.parenttsguid;
                // if(parent != "" && $Variable.spaceInCloud[parent] != deployInfo.cloudname + "_" + deployInfo.areaname){
                //     _Infor("部署区域需要与父节点保持一致",'warning');
                //     loadItem();
                //     return resolve(-1);
                // }
                paramMap._insert("deployCloudGUID", deployInfo.cloudguid, "string"); // string;部署云区域GUID
                paramMap._insert("areaID", deployInfo.areaid, "int32");  // int32;数据区ID
                paramMap._insert("cloudAreaName", [deployInfo.cloudname, deployInfo.areaname], "string[]");                 
            }
        }

        const input = new StringMap({
            identifierType: CALL_BY_NAME,
            name: $Variable.spaceTimeObjectName,
            funcname: "IDeployPUInstances",
            params: [new Variant(paramMap)]
        });

        let pjtMngSTFullPath = $Variable.spaceTimeObjectFullPath;
        let runInfo = {
            stType: 5, // FULLNAME，使用全路径名标识，其他标识参数无效
            spaceTime: pjtMngSTFullPath // 目标页面的时空属性，和sTType配合使用
        }
        SetRunInfo(runInfo, async function(resData) {
            if (0 === resData.ret) {

                let res = await Call(PARAM_PUBLIC, input);

                try {
                    if (0 !== res.ret) {
                        let errormsg = "请求发送失败！请检查后台服务是否运行正常";
                        _Infor(errormsg, "error");
                        console.log("-E- " + errormsg + "，ret:", res.ret);
                        // 关闭遮罩层
                        loadItem();
                        return resolve(-1);
                    }

                    if (res.errorcodes) {
                        for (let i = 0; i < res.errorcodes.length; i++) {
                            let res_errorcode = res.errorcodes[i];
                            if (0 !== res_errorcode) {
                                // _Infor("部署失败！", "error");
                                console.log("-E- IDeployPUInstances()接口错误，errorCode:", res_errorcode);
                                // 关闭遮罩层
                                loadItem();
                                return resolve(-1);
                            }
                        }
                    }

                    if (res.returndata) {
                        let res_returndata = res.returndata;
                        if (0 !== res_returndata.errorcode) {
                            // 针对具体报错内容做处理
                            switch (res_returndata.errorcode) {
                                case -11955:
                                    _Infor("时空对象名称重复，请检查该实例是否已在其他云区域部署！", "error");
                                    break;
                                default:
                                    break;
                            }

                            console.log(res_returndata.errormsg);
                            // 关闭遮罩层
                            loadItem();
                            return resolve(-1);
                        }
                        // 获取时空对象GUID
                        let timeSpaceGuid = res_returndata.timespaceguid || "";
                        $Variable.timeSpaceGuids = [];
                        $Variable.timeSpaceGuids.push(timeSpaceGuid);
                        // 获取任务名称
                        let taskName = res_returndata.taskname || "";
                        // 若全部失败，则直接返回
                        if ("" === taskName) {
                            // 关闭遮罩层
                            loadItem();
                            return resolve(-1);
                        }
                        let taskNames = [taskName];

                        // 否则打开进度弹窗，等待成功的执行完成
                        // 配置窗口 top 位置
                        let windowHeight = document.body.clientHeight;
                        let pageHeight = 200;
                        let topPX = "0px";
                        if ((windowHeight - pageHeight) > 0) {
                            topPX = String((windowHeight - pageHeight) / 2 - 100) + "px";
                        }
                        //页面名称
                        let pageName = "运维部署管理_进度展示";
                        //配置项
                        let options = {
                            styleOptions: {
                                header: false,
                                modal: true,
                                width: 700,
                                height: 200,
                                draggable: true,
                                maximizable: false,
                                top: topPX
                            },
                            variables: [{
                                name: "cloudId",
                                value: $Variable.cloudID
                            }, {
                                name: "spaceTimeObjectFullPath",
                                value: $Variable.spaceTimeObjectFullPath
                            }, {
                                name: "spaceTimeObjectName",
                                value: $Variable.spaceTimeObjectName
                            }, {
                                name: "taskNames",
                                value: taskNames
                            }, {
                                name: "commandType",
                                value: $Variable.commandType
                            }, {
                                name: "showText",
                                value: `${$Variable.commandType}中，请等待...`
                            }, {
                                name: "isLastLayer",
                                value: true
                            }, {
                                name: "instRepoGUIDArr",
                                value: [timeSpaceGuid]
                            }]
                        };

                        ShowChild(pageName, options, (res) => {
                            debugger

                            let taskFailedCount = 0;
                            if (res.eventName == "closePageEvent") {
                                if (res.eventParam.length > 0) {
                                    taskFailedCount = res.eventParam[0].taskFailedCount;
                                }
                                CloseChild(pageName);
                            }

                            if (taskFailedCount > 0) {
                                return resolve(-1);
                            } else {
                                $Variable.deployInfo = "";
                                return resolve(0);
                            }
                        });
                        setTimeout(function() {
                            // 关闭遮罩层
                            loadItem();
                        }, 1000);
                    }
                } catch (e) {
                    // _Infor("部署失败！", "error");
                    console.log(e);
                    // 关闭遮罩层
                    loadItem();
                    return resolve(-1);
                }
            } else {
                let errormsg = resData.msg;
                // _Infor(errormsg, "error");
                console.log("-E- " + errormsg + "，ret:", resData.ret);
                // 关闭遮罩层
                loadItem();
                return resolve(-1);
            }
        });
    });
}

async function main() {
    if ($Variable.selectPUInstancesList.length <= 0) {
        _Infor("请选择节点！", "error");
        return;
    }

    // 设置指令类型
    $Variable.commandType = "部署";

    console.time("部署耗时");

    let puInstanceItem = $Variable.selectPUInstancesList[0];

    // 部署生产单元实例
    let retCode = await _DeployPUInstances(puInstanceItem);
    if (0 !== retCode) {
        _Infor(`${$Variable.commandType}失败！`, "error");
    } else {
        _Infor(`${$Variable.commandType}成功！`, "success");
    }

    console.timeEnd("部署耗时");

    // 触发执行刷新生产单元实例信息函数
    $Variable.queryPUInstancesInfo = !$Variable.queryPUInstancesInfo;

    return;
}

main();

