// 按rowIndex层级分组
function groupByRowIndex(originalData) {
    try {
        // 按rowIndex层级分组
        let levelsByRowIndex = groupByRowIndexLevel(originalData);
        console.log(`按rowIndex层级分组完成，共 ${levelsByRowIndex.length} 层`);
        return levelsByRowIndex;
    } catch (error) {
        console.log(`按rowIndex分组时出错: ${error.message}`);
        return -1;
    }
}

// 按rowIndex层级分组算法
function groupByRowIndexLevel(data) {
    // 计算每个节点的层级深度
    const nodesWithLevel = data.map(node => {
        // 根据rowIndex中的"-"数量确定层级
        const level = node.rowIndex.split('-').length - 1;
        return {
            ...node,
            level: level
        };
    });

    // 按层级分组
    const levels = {};
    nodesWithLevel.forEach(node => {
        if (!levels[node.level]) {
            levels[node.level] = [];
        }
        levels[node.level].push(node);
    });

    // 转换为按层级排序的数组
    const sortedLevels = [];
    const levelKeys = Object.keys(levels).map(Number).sort((a, b) => a - b);
    levelKeys.forEach(level => {
        sortedLevels.push({
            level: level,
            nodes: levels[level]
        });
    });

    return sortedLevels;
}

async function main() {
    // 校验数据长度
    if (0 === $Variable.selectPUInstancesList.length) {
        _Infor("请选择节点！", "error");
        return;
    }

    // 设置操作类型
    $Variable.commandType = "批量撤销部署";

    // TODO:校验选中项是否正常

    console.time("批量撤销部署耗时");

    // 按rowIndex层级分组
    let levelsByRowIndex = groupByRowIndex($Variable.selectPUInstancesList);
    if (-1 === levelsByRowIndex) {
        _Infor("层级分组失败！", "error");
        return;
    }

    // 数组倒序
    let levelsByRowIndexReverse = levelsByRowIndex.reverse();

    try {
        let bAllSuccess = true;
        // 按层级顺序处理
        let currentLevel = levelsByRowIndexReverse[0];
        let isLastLayer = false;
        $Variable.totalLayer = levelsByRowIndexReverse.length;
        if ((levelsByRowIndexReverse.length - 1) === 0) {
            isLastLayer = true;
        }
        let finalResult;
        let partSlice = 0;
        let partLayer = 0
        let totalData;
        let partData;
        let partLevel = {};
        if(currentLevel.nodes.length > 100){
            $Variable.totalSlice = Math.floor(currentLevel.nodes.length/100);
            totalData = currentLevel.nodes;
            partData = totalData.slice(0, 100);
            partLevel.level = currentLevel.level;
            partLevel.nodes = partData;
            finalResult = await _BatchUndeployPUInstances(partLevel, false, levelsByRowIndexReverse);            
        }else{
            $Variable.totalSlice = 0;
            finalResult = await _BatchUndeployPUInstances(currentLevel, isLastLayer, levelsByRowIndexReverse);            
        }         

        if (bAllSuccess) {
            _Infor(`${$Variable.commandType}成功`, "success");
