        if ((levelsByRowIndexReverse.length - 1) === 0) {
            isLastLayer = true;
        }
        let finalResult;
        let partSlice = 0;
        let partLayer = 0
        let totalData;
        let partData;
        let partLevel = {};
        if(currentLevel.nodes.length > 100){
            $Variable.totalSlice = Math.floor(currentLevel.nodes.length/100);
            totalData = currentLevel.nodes;
            partData = totalData.slice(0, 100);
            partLevel.level = currentLevel.level;
            partLevel.nodes = partData;
            finalResult = await _BatchStopPUInstances(partLevel, false, levelsByRowIndexReverse);            
        }else{
            $Variable.totalSlice = 0;
            finalResult = await _BatchStopPUInstances(currentLevel, isLastLayer, levelsByRowIndexReverse);            
        }        

        if (bAllSuccess) {
            _Infor(`${$Variable.commandType}成功`, "success");
        }
    } catch (error) {
        console.log(`处理层级时出错: ${error.message}`);
    }

    console.timeEnd("批量停止耗时");

    // 触发执行刷新生产单元实例信息函数
    $Variable.queryPUInstancesInfo = !$Variable.queryPUInstancesInfo;

    return;
}

