// 遮罩层校验实际时空对象和时空仓库状态函数
function loadingFunc(repoGUID) {
    return new Promise(async (resolve, reject) => {

        // 获取当前操作的期望结果
        let expectedResult = getExpectedResult($Variable.commandType);

        // 设置标志位参数
        let bVerifySTObjFlag = false;
        let bVerifySTRepoCfgFlag = false;

        // // 校验操作的实际状态
        try {
            // 查询校验时空对象和时空仓库的部署、运行状态
            // console.log("》》》开始查询时空对象：" + `${repoGUID}的状态`);
            if (!bVerifySTObjFlag && "部分更新"!=$Variable.order) {
                // 先查询校验时空对象的部署、运行状态是否符合预期
                let stObjectInfo = await querySTObjectInfo([repoGUID]);
                for (let i = 0; i < stObjectInfo.length; i++) {
                    if ((expectedResult === stObjectInfo[i].deploy_state) || (expectedResult === stObjectInfo[i].running_state)) {
                        bVerifySTObjFlag = true; // 校验成功，则开始校验时空仓库的状态
                        break;
                    }
                }
            }
            // console.log("《、《、结束查询时空对象：" + `${repoGUID}的状态`);
            // 根据类型判断状态
            if (("撤销部署" === $Variable.commandType) || ("批量撤销部署" === $Variable.commandType)) {
                // 状态全部校验通过，撤销部署特殊处理
                if (bVerifySTObjFlag) {
                    return resolve(0);
                }
            } else {
                if (bVerifySTObjFlag || "部分更新" == $Variable.order) {
                    // 当时空对象状态校验通过后，才开始查询校验时空仓库的部署、运行状态是否符合预期
                    // console.log("》》》开始校验时空对象：" + `${repoGUID}下时空仓库的状态`);
                    let stRepoCfgInfo = await querySTRepoCfgInfo(repoGUID);
                    for (let i = 0; i < stRepoCfgInfo.length; i++) {
                        if ((expectedResult === stRepoCfgInfo[i].deploy_state) || (expectedResult === stRepoCfgInfo[i].running_state)) {
                            bVerifySTRepoCfgFlag = true; // 全部校验成功，则执行关闭遮罩层操作
                        } else {
                            bVerifySTRepoCfgFlag = false; // 若某个校验失败，则继续轮询校验状态
                            console.log(`${$Variable.commandType}中，时空${repoGUID}存在时空仓库状态不匹配`);
                            break;
                        }
                    }
                    // console.log("《、《、结束校验时空对象：" + `${repoGUID}下时空仓库的状态`);
                    if(stRepoCfgInfo.length==0){
                        bVerifySTRepoCfgFlag = true;
                    }
                }

                // 状态全部校验通过，撤销部署特殊处理
                if (bVerifySTRepoCfgFlag) {
                    return resolve(0);
                }
            }

            // 否则返回失败
            return resolve(-1);
        } catch (error) {
            console.error(error);
            return resolve(-1);
        }
    });
}

async function main() {
    // 设置文本内容
    标题栏文本.text = `${$Variable.commandType}进度`;
    详情展示文本.text = $Variable.showText;

    let taskNames = $Variable.taskNames;
    if (taskNames.length > 0) {
        // 设置轮询参数
        const pollInterval = 500; // 500毫秒
        let MAX_COUNT = 2400; // 检验的最大循环次数（20分钟）
        let loopCount = 0; // 初始化循环计数
        let continueExec = true; // 默认为继续执行
        // 轮询查询任务状态
        // console.log($Variable.showText + "======》开始执行查询任务进度");
        while ((loopCount < MAX_COUNT) && continueExec) {
            try {
                // 延时等待
                await sleep(pollInterval);
                // 更新计数
                loopCount++
                // 调配置后台接口
                let taskInfoList = await queryTaskByNames(taskNames);
                // 解析返回值的状态
                let totalProgress = 0;
                let successTaskCount = 0;
                let newTaskNames = [];
                for (let i = 0; i < taskInfoList.length; i++) {
                    let taskInfoItem = taskInfoList[i];

                    if (taskStatus.ERROR === taskInfoItem.status) {
                        $Variable.taskFailedCount++;
                        continue;
                    }
                    totalProgress += taskInfoItem.progress;
                    successTaskCount++;
                    if (!((taskStatus.COMPLETE === taskInfoItem.status) && (100 === taskInfoItem.progress))) {
                        newTaskNames.push(taskInfoItem.taskname);
                    }
                }
                // 更新进度
                const progress = Math.floor(totalProgress / successTaskCount);
                if (progress <= 100) {
                    taskProgress_VantProgress.$el.querySelector(".van-progress__portion").style.width = `${progress}%`;
                    taskProgress_ElementText.text = `${progress}%`;
                }
                // 更新标志位
                continueExec = false;
                if (newTaskNames.length > 0) {
                    continueExec = true;
                    taskNames = newTaskNames;
                }else{
                    console.log("当前没有待查询任务，进度为：" + `${progress}`);
                }
            } catch (error) {
                console.error(error);
            }
        }
        // console.log($Variable.showText + "======》结束查询任务进度");
        if (loopCount < MAX_COUNT) {
            // 清空当前层时空对象下的时空仓库
            if (("撤销部署" === $Variable.commandType) || ("批量撤销部署" === $Variable.commandType)) {
                await _DeleteSTRepoCfg();
            }
            // 并发校验状态
            // console.log($Variable.showText + "======》开始执行查询时空和时空仓库状态");
            const batchPromises = $Variable.instRepoGUIDArr.map(instRepoGUID =>
                loadingFunc(instRepoGUID)
            );
            // 等待全部执行完毕
            const batchResults = await Promise.all(batchPromises);
            // console.log($Variable.showText + "======》结束查询时空和时空仓库状态");
            // 返回数据校验
            let failedCount = 0;
            for (let i = 0; i < batchResults.length; i++) {
                if (0 !== batchResults[i]) {
                    failedCount++;
                }
            }
            // 判断当前层是否成功
            if (failedCount > 0) {
                $Variable.taskFailedCount++;
                // 更新弹窗展示状态
                close_ElementButton.button({
                    disabled: false
                });
                closePage_ElementButton.button({
                    disabled: false,
                    text: "失败",
                    loading: false,
                    backgroundColor: "#DC2626",
                    color: "#FFFFFF"
                });
            } else {
                // 判断是否为最后一层
                if (!$Variable.isLastLayer) {
                    // 关闭进度展示窗
                    $Event.closePageEvent({
                        "taskFailedCount": $Variable.taskFailedCount
                    });
                } else {
                    // 停留在成功页面
                    close_ElementButton.button({
                        disabled: false
                    });
                    closePage_ElementButton.button({
                        disabled: false,
                        text: "成功",
                        loading: false,
                        backgroundColor: "#15803D",
                        color: "#FFFFFF"
                    });
                }
            }
        } else {
            _Infor("进度条更新超时，请检查后重试！", "error");
            close_ElementButton.button({
                disabled: false
            });
            closePage_ElementButton.button({
                disabled: false,
                text: "失败",
                loading: false,
                backgroundColor: "#DC2626",
                color: "#FFFFFF"
            });
        }
    } else {
        _Infor("任务名称列表为空，请检查后重试！", "error");
        close_ElementButton.button({
            disabled: false
        });
        closePage_ElementButton.button({
            disabled: false,
            text: "失败",
            loading: false,
            backgroundColor: "#DC2626",
            color: "#FFFFFF"
        });
    }
}

main();

