        // 轮询查询任务状态
        // console.log($Variable.showText + "======》开始执行查询任务进度");
        let successTaskCount = 0;
        let taskLen = taskNames.length;
        let overTimeCount = 0;
        let delTask = [];        
        while ((loopCount < MAX_COUNT) && continueExec) {
            try {
                // 延时等待
                await sleep(pollInterval);
                // 更新计数
                loopCount++
                // 调配置后台接口
                let taskInfoList = await queryTaskByNames(taskNames);
                // 解析返回值的状态
                let totalProgress = 0;
                let newTaskNames = [];
                for (let i = 0; i < taskInfoList.length; i++) {
                    let taskInfoItem = taskInfoList[i];

                    if (taskStatus.ERROR === taskInfoItem.status) {
                        $Variable.taskFailedCount++;
                        continue;
                    }
                    totalProgress += taskInfoItem.progress;
                    if (!((taskStatus.COMPLETE === taskInfoItem.status) && (100 === taskInfoItem.progress))) {
                        newTaskNames.push(taskInfoItem.taskname);
                    }else if(taskStatus.COMPLETE === taskInfoItem.status && 100 === taskInfoItem.progress){
                        successTaskCount++;
                    }
                }
                // 更新进度
                const progress = Math.floor(($Variable.finishedTask+successTaskCount)*100 / $Variable.totalTask);
                if (progress <= 100) {
                    taskProgress_VantProgress.$el.querySelector(".van-progress__portion").style.width = `${progress}%`;
                    taskProgress_ElementText.text = `${$Variable.finishedTask+successTaskCount}` + "/" + `${$Variable.totalTask}`;
                }
                // 更新标志位
                continueExec = false;
                if (newTaskNames.length > 0) {
                    continueExec = true;
                    taskNames = newTaskNames;
                    if(overTimeCount > 60){
                        console.log("当前任务超时");
                        continueExec = false;
                        delTask = newTaskNames;
                    }
                    
                    if(newTaskNames.length != taskLen){
                        taskLen = newTaskNames.length;
                        overTimeCount = 0;
                    }else{
                        overTimeCount++;
                    }                    
                }else{
                    $Variable.finishedTask = $Variable.finishedTask + successTaskCount;
                    console.log("当前没有待查询任务，进度为：" + `${progress}`);
                }
            } catch (error) {
                console.error(error);
            }
        }
        // console.log($Variable.showText + "======》结束查询任务进度");
        if (loopCount < MAX_COUNT) {
            // 超时删除任务
            if(delTask.length > 0){
                let tarTask = new Variant(delTask, "string[]");
                let delInput = new StringMap({
