// 基于 Promise 的 sleep 函数
function sleep(ms) {
    return new Promise(resolve => setTimeout(resolve, ms));
}

// 获取期望结果函数
function getExpectedResult(command) {
    let result = "";
    switch (command) {
        case '部署':
        case '批量部署':
        case '部署实例':
            result = "已部署";
            break;
        case '撤销部署':
        case '批量撤销部署':
        case '反部署实例':
            result = "未部署";
            break;
        case '启动':
        case '批量启动':
            result = "已启动";
            break;
        case '停止':
        case '批量停止':
            result = "未启动";
            break;
        case '更新':
        case '回退':
            result = "已启动";
            break;
        default:
            break;
    }
    return result;
}

