const CALL_BY_NAME = 2;
const API_TYPE = 21001; // 接口类型标识
const TIMEOUT = 1000 * 60 * 5; // 接口请求超时时间
const PARAM_PUBLIC = new StringMap({
    "cloudID": $Variable.cloudId,
    "type": API_TYPE,
    "timeout": TIMEOUT
});

// 任务状态
const taskStatus = {
    PRAPARE: 0, // 准备
    RUNNING: 1, // 进行中
    ERROR: 2, // 错误
    COMPLETE: 3, // 完成
    CANCEL: 4, // 取消
};

// 消息提示窗函数
function _Infor(massage, type) {
    var options = {
        message: massage,
        type: type,
        duration: 3000,
        showClose: true
    };
    ShowMessage(options);
}

// 基于 Promise 的 sleep 函数
function sleep(ms) {
    return new Promise(resolve => setTimeout(resolve, ms));
}

// 获取期望结果函数
function getExpectedResult(command) {
    let result = "";
    switch (command) {
        case '部署':
        case '批量部署':
        case '部署实例':
            result = "已部署";
            break;
        case '撤销部署':
        case '批量撤销部署':
        case '反部署实例':
            result = "未部署";
            break;
        case '启动':
        case '批量启动':
            result = "已启动";
            break;
        case '停止':
        case '批量停止':
            result = "未启动";
            break;
        case '更新':
        case '回退':
            result = "已启动";
            break;
        default:
            break;
    }
    return result;
}

// 删除时空仓库函数（撤销部署使用）
function _DeleteSTRepoCfg() {
    return new Promise((resolve, reject) => {

        let inputParamMap = new StringMap({});
        inputParamMap._insert("toDelSTRepoCfgData", $Variable.instRepoGUIDArr, "string[]"); // string[];时空对象GUID数组

        const input = new StringMap({
            identifierType: CALL_BY_NAME,
            name: $Variable.spaceTimeObjectName,
            funcname: "IDeleteSTRepoCfg",
            params: [new Variant(inputParamMap)]
        });

        let pjtMngSTFullPath = $Variable.spaceTimeObjectFullPath;
        let runInfo = {
            stType: 5, // FULLNAME，使用全路径名标识，其他标识参数无效
            spaceTime: pjtMngSTFullPath // 目标页面的时空属性，和sTType配合使用
        }
        SetRunInfo(runInfo, async (resData) => {
            if (0 === resData.ret) {

                let res = await Call(PARAM_PUBLIC, input);

                try {
                    if (0 !== res.ret) {
                        let errormsg = "请求发送失败！请检查后台服务是否运行正常";
                        _Infor(errormsg, "error");
                        console.log("-E- " + errormsg + "，errorCode:" + res.ret);
                        return resolve(-1);
                    }

                    if (res.errorcodes) {
                        for (let i = 0; i < res.errorcodes.length; i++) {
                            let res_errorcode = res.errorcodes[i];
                            if (0 !== res_errorcode) {
                                _Infor("删除时空仓库失败！", "error");
                                console.log("-E- IDeleteSTRepoCfg()接口错误，errorCode:" + res_errorcode);
                                return resolve(-1);
                            }
                        }
                    }

                    if (res.returndata) {
                        let res_returndata = res.returndata;
                        if (0 !== res_returndata.errorcode) {
                            _Infor("删除时空仓库失败！", "error");
                            console.log("-E- " + res_returndata.errormsg + "，errorCode:" + res_returndata.errorcode);
                            return resolve(-1);
                        }

                        return resolve(0);
                    }

                } catch (error) {
                    // 保留原始错误栈信息 
                    console.log(`-E- 删除时空仓库失败！${error.message}`);
                    return resolve(-1);
                }
            } else {
                let errormsg = resData.msg;
                console.log("-E- " + errormsg + "，errorCode:" + resData.ret);
                return resolve(-1);
            }
        });
    });
}

